import torchaudio
from speechbrain.pretrained import EncoderClassifier
import torch

classifier = EncoderClassifier.from_hparams(source="speechbrain/spkrec-ecapa-voxceleb")

train_sample1 = [
    "/content/minispeakerdiarization2/dataset/train/anthropology_professor/audio_1.wav",
    "/content/minispeakerdiarization2/dataset/train/biology_professor/audio_1.wav",
    "/content/minispeakerdiarization2/dataset/train/customer/audio_1.wav",
    "/content/minispeakerdiarization2/dataset/train/literature_professor/audio_1.wav",
    "/content/minispeakerdiarization2/dataset/train/physics_professor/audio_1.wav",
    "/content/minispeakerdiarization2/dataset/train/store_clerk/audio_1.wav"
]

def extract_embeddings(audio_paths):
    embeddings = []
    for path in audio_paths:
        signal, fs = torchaudio.load(path)
        emb = classifier.encode_batch(signal)
        embeddings.append(emb.squeeze().cpu().numpy())
    return embeddings

embeddings = extract_embeddings(train_sample1)

import numpy as np
embeddings_array = np.array(embeddings)

print(embeddings_array.shape)

