from sklearn.preprocessing import normalize

normalized_embeddings = normalize(flattened_embeddings, norm='l2')

normalized_embeddings.shape

"""Similarity matrix"""

from sklearn.metrics.pairwise import cosine_similarity

similarity_matrix = cosine_similarity(normalized_embeddings)

plt.figure(figsize=(10, 6))
sns.heatmap(similarity_matrix, cmap='coolwarm', annot=True, fmt=".2f")
plt.title("Cosine Similarity Matrix of Speaker Embeddings")
plt.xlabel("Segment Index")
plt.ylabel("Segment Index")
plt.show()

"""Affinity matrix building"""

import numpy as np

# Optional: Gaussian kernel (better for spectral clustering)
sigma = 0.5  # you can tune this
affinity_matrix = np.exp(-1 * (1 - similarity_matrix) ** 2 / (2. * sigma ** 2))

plt.figure(figsize=(10, 6))
sns.heatmap(affinity_matrix, cmap='viridis', annot=True, fmt=".2f")
plt.title("Affinity Matrix (Gaussian Kernel) of Speaker Embeddings")
plt.xlabel("Segment Index")
plt.ylabel("Segment Index")
plt.show()

"""Clsutering"""

from sklearn.cluster import SpectralClustering

n_speakers = 6  # Set this based on your data
spectral_model = SpectralClustering(n_clusters=n_speakers, affinity='precomputed', assign_labels='kmeans', random_state=42)
labels = spectral_model.fit_predict(affinity_matrix)

unique_labels = np.unique(labels)
print("Unique cluster labels:", unique_labels)


print(f"Number of clusters: {len(unique_labels)}")


print("Speaker labels for each segment:", labels)

