import pandas as pd
import numpy as np
import matplotlib.pyplot as plt

kmeans_df = pd.read_csv('/content/KMenans_Evaluation_Metrics.csv')
sc_df = pd.read_csv('/content/SC_Evlaution_Metrics.csv')

assert all(kmeans_df['File Name'] == sc_df['File Name']), "Mismatch in file names."

metrics = ['DER', 'Accuracy']
labels = kmeans_df['File Name'].tolist()
angles = np.linspace(0, 2 * np.pi, len(labels), endpoint=False).tolist()
angles += angles[:1]

fig, axes = plt.subplots(1, 2, figsize=(16, 8), subplot_kw=dict(polar=True))
fig.suptitle('KMeans vs Spectral Clustering: DER & Accuracy Comparison', fontsize=16, y=1.05)

for i, metric in enumerate(metrics):
    ax = axes[i]

    kmeans_values = kmeans_df[metric].tolist()
    sc_values = sc_df[metric].tolist()
    kmeans_values.append(kmeans_values[0])
    sc_values.append(sc_values[0])
    metric_labels = labels + [labels[0]]

    ax.plot(angles, kmeans_values, label='KMeans', color='skyblue', linewidth=2)
    ax.fill(angles, kmeans_values, color='skyblue', alpha=0.25)

    ax.plot(angles, sc_values, label='Spectral', color='salmon', linewidth=2)
    ax.fill(angles, sc_values, color='salmon', alpha=0.25)

    ax.set_title(metric, size=14, pad=20)
    ax.set_xticks(angles[:-1])
    ax.set_xticklabels(labels, fontsize=10)
    ax.set_rlabel_position(30)
    ax.yaxis.grid(True)
    ax.xaxis.grid(True)
    ax.set_ylim(0, max(max(kmeans_values), max(sc_values)) * 1.1)
    ax.legend(loc='upper right', bbox_to_anchor=(1.2, 1.1))

plt.tight_layout()
plt.show()

